const items = $input.all();

const logEntry = {
  timestamp: new Date().toISOString(),
  workflowRun: 'Classroom Scheduling Analysis',
  totalItems: items.length,
  results: items.map(item => ({
    status: item.json.output?.schedulingRecommendations?.overallStatus || 'Unknown',
    escalationRequired: item.json.output?.schedulingRecommendations?.escalationRequired || false,
    conflictsCount: item.json.output?.schedulingRecommendations?.conflicts?.length || 0,
    scheduledCourses: item.json.output?.schedulingRecommendations?.optimalSchedule?.length || 0
  }))
};

console.log('=== Scheduling Workflow Completed ===');
console.log(JSON.stringify(logEntry, null, 2));

return [{ json: logEntry }];

try {
  const conflicts = typeof query === 'string' ? JSON.parse(query) : query;

  if (!Array.isArray(conflicts) || conflicts.length === 0) {
    return JSON.stringify({ totalScore: 0, breakdown: [], riskLevel: 'NONE' });
  }

  // Severity weights
  const severityWeights = {
    'CRITICAL': 10,
    'HIGH': 5,
    'MEDIUM': 2,
    'LOW': 1
  };

  // Calculate conflict scores
  const breakdown = conflicts.map(conflict => {
    const severityScore = severityWeights[conflict.severity] || 1;
    const affectedCount = (conflict.affectedCourses || []).length;
    const complexityFactor = affectedCount > 2 ? 1.5 : 1.0;

    const score = severityScore * affectedCount * complexityFactor;

    return {
      conflictId: conflict.conflictId || 'unknown',
      type: conflict.type || 'unknown',
      severity: conflict.severity || 'LOW',
      score: Math.round(score * 10) / 10,
      affectedCourses: affectedCount
    };
  });

  const totalScore = breakdown.reduce((sum, item) => sum + item.score, 0);

  // Determine risk level
  let riskLevel = 'LOW';
  if (totalScore > 50) riskLevel = 'CRITICAL';
  else if (totalScore > 25) riskLevel = 'HIGH';
  else if (totalScore > 10) riskLevel = 'MEDIUM';

  const result = {
    totalScore: Math.round(totalScore * 10) / 10,
    breakdown,
    riskLevel,
    conflictCount: conflicts.length,
    criticalCount: conflicts.filter(c => c.severity === 'CRITICAL').length,
    highCount: conflicts.filter(c => c.severity === 'HIGH').length
  };

  return JSON.stringify(result, null, 2);

} catch (error) {
  return `Error calculating conflict scores: ${error.message}`;
}

const schedulingData = $input.first().json;
const historicalDays = $('Workflow Configuration').first().json.historicalDataDays || 90;

// Simulate historical scheduling patterns analysis
// In production, this would query a database of past schedules
const classrooms = schedulingData.classrooms || [];
const faculty = schedulingData.faculty || [];

const historicalPatterns = {
  classroomUtilization: classrooms.map(room => ({
    classroomId: room.id,
    avgUtilization: Math.random() * 0.4 + 0.5, // 50-90%
    peakHours: ['09:00-12:00', '14:00-16:00'],
    preferredDays: ['Monday', 'Wednesday', 'Friday'],
    conflictFrequency: Math.random() * 0.2 // 0-20%
  })),
  facultyPreferences: faculty.map(fac => ({
    facultyId: fac.id,
    preferredTimeSlots: fac.preferredTimeSlots || [],
    avgClassesPerDay: Math.random() * 2 + 2, // 2-4 classes
    cancellationRate: Math.random() * 0.1, // 0-10%
    studentSatisfactionScore: Math.random() * 0.3 + 0.7 // 70-100%
  })),
  conflictTrends: {
    totalConflictsLast90Days: Math.floor(Math.random() * 50 + 10),
    mostCommonConflictType: 'Equipment Unavailability',
    resolutionSuccessRate: 0.78,
    avgResolutionTime: '2.5 hours'
  },
  seasonalPatterns: {
    highDemandPeriods: ['September-October', 'January-February'],
    lowDemandPeriods: ['June-August', 'December'],
    examPeriodAdjustments: true
  },
  analysisDate: new Date().toISOString(),
  dataRangeDays: historicalDays
};

return [{ json: { historicalPatterns, originalData: schedulingData } }];

const data = $input.first().json;

const conflictReport = {
  resolutionType: 'MANUAL_ESCALATION',
  escalationTimestamp: new Date().toISOString(),
  decision: data.output?.finalDecision || {},
  conflictSummary: {
    totalConflictScore: data.output?.finalDecision?.conflictScoreTotal || 0,
    riskLevel: data.output?.finalDecision?.riskAssessment || 'UNKNOWN',
    cannotAutoResolveReason: data.output?.finalDecision?.reasoning || 'Insufficient confidence or high-risk conflicts detected',
    requiresHumanReview: true
  },
  recommendedActions: data.output?.finalDecision?.recommendedActions || [],
  escalationPriority: data.output?.finalDecision?.conflictScoreTotal > 30 ? 'URGENT' : 'STANDARD',
  reportGeneratedAt: new Date().toISOString()
};

return [{ json: { ...data, conflictReport } }];

